import{c as s,Q as a,j as t,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The 7 Claude Code Mistakes That Mass Waste Your Tokens — @zodchiii","description":"","frontmatter":{"title":"The 7 Claude Code Mistakes That Mass Waste Your Tokens — @zodchiii","author":"darkzodchi（@zodchiii）","date":"2026-05-13T00:00:00.000Z","source":"https://x.com/zodchiii/status/2054492434831135095","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-13-@zodchiii-135095.md","filePath":"research/tweets/2026-05-13-@zodchiii-135095.md","lastUpdated":1779898012000}'),i={name:"research/tweets/2026-05-13-@zodchiii-135095.md"};function o(r,e,l,p,h,d){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="the-7-claude-code-mistakes-that-mass-waste-your-tokens-—-zodchiii" tabindex="-1">The 7 Claude Code Mistakes That Mass Waste Your Tokens — @zodchiii <a class="header-anchor" href="#the-7-claude-code-mistakes-that-mass-waste-your-tokens-—-zodchiii" aria-label="Permalink to &quot;The 7 Claude Code Mistakes That Mass Waste Your Tokens — @zodchiii&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/zodchiii/status/2054492434831135095" target="_blank" rel="noreferrer">https://x.com/zodchiii/status/2054492434831135095</a><strong>作者</strong>：darkzodchi（@zodchiii） <strong>發布日期</strong>：2026-05-13 <strong>收錄日期</strong>：2026-05-27（重新收錄，補全 11 個 MARKDOWN code block） <strong>類型</strong>：Twitter Article <strong>統計</strong>：99 likes · 8 retweets · 0 bookmarks · 46815 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Claude Code resends your entire conversation history on every single turn. A 30-message session burns 232,000 tokens. Every MCP server, every skill, every file Claude has read travels with you silently. Most people think Claude got worse. It didn&#39;t. Their setup is eating tokens before the first prompt lands. Here are the 7 mistakes that cost you the most 👇 Before we dive in, I share daily notes on AI &amp; vibe coding in my Telegram channel: <a href="https://t.me/zodchixquant%F0%9F%A7%A0" target="_blank" rel="noreferrer">https://t.me/zodchixquant🧠</a> [圖 1]</p><h2 id="mistake-1-using-opus-for-everything" tabindex="-1">Mistake 1: Using Opus for everything <a class="header-anchor" href="#mistake-1-using-opus-for-everything" aria-label="Permalink to &quot;Mistake 1: Using Opus for everything&quot;">​</a></h2><p>Opus costs 5x more than Sonnet per token. On subscription plans, it drains your 5-hour window roughly 5x faster. Most coding tasks don&#39;t need Opus-level reasoning.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model sonnet    → daily coding, reviews, tests, refactoring</span></span>
<span class="line"><span>/model opus      → complex architecture, multi-file debugging</span></span>
<span class="line"><span>/model haiku     → quick questions, formatting, renaming</span></span></code></pre></div><p>Start every session on Sonnet. Switch to Opus only when you genuinely need deep reasoning. Switch to Haiku for throwaway questions. This alone can cut your token burn in half. For subagents, route them to cheaper models:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export CLAUDE_CODE_SUBAGENT_MODEL=&quot;claude-sonnet-4-5-20250929&quot;</span></span></code></pre></div><p>Your main session runs Opus for complex reasoning while subagents handle focused tasks on Sonnet.</p><h2 id="mistake-2-never-running-compact-or-running-it-too-late" tabindex="-1">Mistake 2: Never running /compact (or running it too late) <a class="header-anchor" href="#mistake-2-never-running-compact-or-running-it-too-late" aria-label="Permalink to &quot;Mistake 2: Never running /compact (or running it too late)&quot;">​</a></h2><p>Every message adds to your context. By message 20, Claude is re-reading everything from message 1 on every turn. Autocompact triggers at ~95% capacity by default, but by then your session is already bloated. Set an earlier trigger:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Compact at 70% for normal work</span></span>
<span class="line"><span>Compact at 50% for noisy workflows (log analysis, debugging)</span></span></code></pre></div><p>And use custom instructions when compacting:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact preserve architecture decisions, files changed, failing tests, and next steps</span></span></code></pre></div><p>Default /compact drops everything equally. Custom instructions keep what matters and cut what doesn&#39;t. The timing rule: compact when the productive part of the conversation is clear, not when Claude starts forgetting things. A healthy session produces a better summary than a degraded one.</p><h2 id="mistake-3-mcp-servers-loaded-that-you-re-not-using" tabindex="-1">Mistake 3: MCP servers loaded that you&#39;re not using <a class="header-anchor" href="#mistake-3-mcp-servers-loaded-that-you-re-not-using" aria-label="Permalink to &quot;Mistake 3: MCP servers loaded that you&#39;re not using&quot;">​</a></h2><p>Every connected MCP server loads its full tool definitions and schema into your context on every turn. Some servers add 18,000+ tokens just sitting there. Stack 5 servers and that&#39;s 90,000 tokens of overhead before your first prompt. Every turn.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mcp</span></span></code></pre></div><p>Check which servers are connected. Remove any you&#39;re not actively using this session. Each removed server saves thousands of tokens per turn. One developer found 160 registered skills eating ~25,000 tokens per call. Another had a system prompt bloated to 607,000 tokens from accumulated plugins and MCP servers. Vercel&#39;s agent evaluations found skills were never invoked in 56% of test cases. More than half your tools might just be sitting there, eating budget and doing nothing.</p><h2 id="mistake-4-no-preprocessing-hooks-for-large-files" tabindex="-1">Mistake 4: No preprocessing hooks for large files <a class="header-anchor" href="#mistake-4-no-preprocessing-hooks-for-large-files" aria-label="Permalink to &quot;Mistake 4: No preprocessing hooks for large files&quot;">​</a></h2><p>Claude reading a 10,000-line log file costs thousands of tokens. Most of those lines are noise. A preprocessing hook filters before Claude sees it:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PreToolUse&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;matcher&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(cat *log*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;grep -n &#39;ERROR</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">|WARN&#39; $file | head -50&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Claude sees 50 relevant lines instead of 10,000. That&#39;s a 99.5% token reduction on log analysis. Same pattern works for any large file: filter, truncate, or summarize before Claude processes it.</p><h2 id="mistake-5-subagent-fan-out-on-simple-tasks" tabindex="-1">Mistake 5: Subagent fan-out on simple tasks <a class="header-anchor" href="#mistake-5-subagent-fan-out-on-simple-tasks" aria-label="Permalink to &quot;Mistake 5: Subagent fan-out on simple tasks&quot;">​</a></h2><p>Agent teams use approximately 7x more tokens than standard sessions. Each subagent maintains its own context window and runs as a separate Claude instance. For a large refactor across 20 files, this makes sense. For a simple bug fix, you just burned 7x the tokens for no quality improvement. The rule:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Simple bug fix              → single session, no agents</span></span>
<span class="line"><span>Code review                 → 2-3 focused subagents</span></span>
<span class="line"><span>Large refactor across files → agent team makes sense</span></span>
<span class="line"><span>&quot;Improve this codebase&quot;     → never, too vague, infinite token burn</span></span></code></pre></div><p>Vague requests like &quot;improve this codebase&quot; trigger broad scanning. Claude reads dozens of files, explores multiple approaches, and burns tokens on exploration that leads nowhere. Specific requests like &quot;add input validation to the login function in auth.ts&quot; let Claude work efficiently with minimal file reads.</p><h2 id="mistake-6-re-explaining-your-project-every-session" tabindex="-1">Mistake 6: Re-explaining your project every session <a class="header-anchor" href="#mistake-6-re-explaining-your-project-every-session" aria-label="Permalink to &quot;Mistake 6: Re-explaining your project every session&quot;">​</a></h2><p>Without CLAUDE.md and /memory, the first 3-5 messages of every session are wasted on setup. &quot;I&#39;m building a Next.js app with Supabase, the auth is in src/lib/auth/...&quot; That&#39;s 3,000-5,000 tokens per session spent saying things Claude should already know.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/init                → generate CLAUDE.md from your project</span></span>
<span class="line"><span>/memory add &quot;...&quot;    → persist facts between sessions</span></span></code></pre></div><p>CLAUDE.md loads once at session start. /memory persists across sessions. Together they eliminate the re-explanation tax completely. But keep CLAUDE.md lean. A 5,000-token CLAUDE.md costs 5,000 tokens every turn, every session. It should be a lookup table, not a brain dump.</p><h2 id="mistake-7-not-clearing-between-tasks" tabindex="-1">Mistake 7: Not clearing between tasks <a class="header-anchor" href="#mistake-7-not-clearing-between-tasks" aria-label="Permalink to &quot;Mistake 7: Not clearing between tasks&quot;">​</a></h2><p>Finishing a debugging session and starting a new feature in the same chat means Claude carries all the debug context (error logs, stack traces, wrong approaches) into the feature work. Every message now costs more because of context that&#39;s no longer relevant.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/clear    → wipe everything, clean slate (switching tasks completely)</span></span>
<span class="line"><span>/compact  → summarize and continue (staying on same task)</span></span></code></pre></div><p>Two different tools for two different situations. Using /compact when you should /clear means paying tokens for context you&#39;ll never reference again. The rule: new task = new chat. No exceptions.</p><h2 id="the-math" tabindex="-1">The math <a class="header-anchor" href="#the-math" aria-label="Permalink to &quot;The math&quot;">​</a></h2><p>A developer tracked what these changes saved over a month:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BEFORE:</span></span>
<span class="line"><span>- Average session: 230,000 tokens</span></span>
<span class="line"><span>- Opus for everything: 5x cost multiplier</span></span>
<span class="line"><span>- 5 MCP servers loaded: ~90K tokens overhead per turn</span></span>
<span class="line"><span>- No preprocessing: 10K+ tokens per log file</span></span>
<span class="line"><span>- Re-explaining project: 5K tokens per session</span></span>
<span class="line"><span>- Never clearing: context grows until limit</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AFTER:</span></span>
<span class="line"><span>- Average session: 85,000 tokens</span></span>
<span class="line"><span>- Sonnet for 80% of tasks: baseline cost</span></span>
<span class="line"><span>- 2 MCP servers active: ~20K overhead</span></span>
<span class="line"><span>- Preprocessing hooks: 50 tokens per log file</span></span>
<span class="line"><span>- CLAUDE.md + /memory: 0 tokens re-explaining</span></span>
<span class="line"><span>- /clear between tasks: fresh context each time</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Result: ~63% reduction in token usage</span></span>
<span class="line"><span>Same output quality, same work done</span></span></code></pre></div><h2 id="the-one-minute-fix" tabindex="-1">The one-minute fix <a class="header-anchor" href="#the-one-minute-fix" aria-label="Permalink to &quot;The one-minute fix&quot;">​</a></h2><p>If you do nothing else, do these 3 things right now:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 1. Set default model to Sonnet</span></span>
<span class="line"><span>/model sonnet</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 2. Check MCP bloat</span></span>
<span class="line"><span>/mcp</span></span>
<span class="line"><span># Remove anything you&#39;re not using today</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 3. Add preprocessing hook to settings.json</span></span>
<span class="line"><span># (the log filtering hook from Mistake 4)</span></span></code></pre></div><h2 id="three-changes-one-minute-immediate-impact-on-every-session-after-this-one" tabindex="-1">Three changes. One minute. Immediate impact on every session after this one. <a class="header-anchor" href="#three-changes-one-minute-immediate-impact-on-every-session-after-this-one" aria-label="Permalink to &quot;Three changes. One minute. Immediate impact on every session after this one.&quot;">​</a></h2><p>Thanks for reading! I share daily notes on AI, finance, and vibe coding in my Telegram channel: <a href="https://t.me/zodchixquant" target="_blank" rel="noreferrer">https://t.me/zodchixquant</a> [圖 2]</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：7 個 Claude Code token 浪費錯誤（實測量化）：tool_use 濫用/大 context 循環/Hook 過度觸發/不必要 think/未用 subagent/ignore caching/bad CLAUDE.md；含 11 個修復 code block</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li><strong>7 個核心錯誤</strong>：①過度 tool_use（單步可完成的任務分成多個工具呼叫）②大 context 循環（每次迭代重傳完整歷史）③Hook 過度觸發（每個 tool call 都跑 hook）④不必要的 extended thinking（簡單任務啟用）⑤未用 subagent 隔離 context⑥忽略 prompt caching⑦bad CLAUDE.md（過長/過頻繁引用）</li><li><strong>修復策略</strong>：使用 TodoWrite 批次規劃；/compact 壓縮循環上下文；hook matcher 精確化；per-task 模型選擇；subagent 隔離複雜子任務</li><li><strong>量化視角</strong>：文章提供每個錯誤的 token 浪費估算（具體數字見 code blocks）</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>11 個 code block（settings.json 配置 + hook 腳本 + CLAUDE.md 範例）</li><li>Hook matcher 精確化：<code>&quot;matcher&quot;: &quot;Write|Edit&quot;</code> vs <code>&quot;matcher&quot;: &quot;.*&quot;</code> 的 token 差異</li><li>subagent context 隔離的 token 節省估算</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li><strong>量化數字需驗證</strong>：token 浪費估算基於特定 workload，普適性有限</li><li><strong>部分建議與其他文章衝突</strong>：文章建議減少 tool_use，但 Claude Code 設計本就鼓勵工具呼叫</li><li><strong>hook matcher 過於嚴格的副作用</strong>：精確 matcher 可能導致某些 edge case 漏掉</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>直接可操作性</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>概念新穎度</td></tr><tr><td>C. 證據品質 (20%)</td><td>7/10</td><td>可驗證性</td></tr><tr><td>D. 技術深度 (15%)</td><td>7/10</td><td>技術細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>普適性</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.8/10</strong></td><td>8×0.3+7×0.2+7×0.2+7×0.15+8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：依評分與內容類型決定</p>`,58)])])}const g=s(i,[["render",o]]);export{u as __pageData,g as default};
